#include <gtest/gtest.h>
#include "Vrv32i_alu.h"  // Generated by Verilator

// Test fixture for ALU with Verilator
class ALUTestVerilator : public ::testing::Test {
protected:
    Vrv32i_alu* dut;  // Verilator generated class

    void SetUp() override {
        dut = new Vrv32i_alu;
    }

    void TearDown() override {
        delete dut;
    }
};

// Basic test
TEST_F(ALUTestVerilator, BasicAdd) {
    dut->a = 10;
    dut->b = 5;
    dut->alu_op = 0;  // ADD
    dut->eval();
    EXPECT_EQ(dut->result, 15);
    EXPECT_FALSE(dut->zero);
}

// Random tests
TEST_F(ALUTestVerilator, RandomOperations) {
    for (int i = 0; i < 100; ++i) {
        dut->a = rand() % UINT32_MAX;
        dut->b = rand() % UINT32_MAX;
        dut->alu_op = rand() % 10;
        dut->eval();
        // Add verification logic here - compare with reference model
    }
}

// Corner cases
TEST_F(ALUTestVerilator, OverflowAdd) {
    dut->a = 0xFFFFFFFF;
    dut->b = 1;
    dut->alu_op = 0;  // ADD
    dut->eval();
    EXPECT_EQ(dut->result, 0);  // Wrap around in unsigned
}

TEST_F(ALUTestVerilator, UnderflowSub) {
    dut->a = 0;
    dut->b = 0xFFFFFFFF;
    dut->alu_op = 1;  // SUB
    dut->eval();
    EXPECT_EQ(dut->result, 1);  // 0 - (-1) in unsigned
}

TEST_F(ALUTestVerilator, ShiftBy32) {
    dut->a = 0xAAAAAAAA;
    dut->b = 32;
    dut->alu_op = 6;  // SLL
    dut->eval();
    EXPECT_EQ(dut->result, 0);  // Shift by 32 should be 0
}

TEST_F(ALUTestVerilator, ZeroResult) {
    dut->a = 42;
    dut->b = 42;
    dut->alu_op = 1;  // SUB 42-42=0
    dut->eval();
    EXPECT_EQ(dut->result, 0);
    EXPECT_TRUE(dut->zero);
}

int main(int argc, char **argv) {
    ::testing::InitGoogleTest(&argc, argv);
    return RUN_ALL_TESTS();
}